+pub struct OrphanRequirementEntry {
+    /// Requirement ID (e.g. `R2`).
+    pub requirement_id: String,
+    /// Spec file path.
+    pub spec_path: String,
+    /// Requirement text for context.
+    #[serde(skip_serializing_if = "Option::is_none")]
